// FNV-1a hash — no crypto needed
function hashUrl(url) {
  const s = url.trim().toLowerCase();
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = (h * 16777619) >>> 0; }
  return h.toString(16).padStart(8,'0');
}
return $input.all().map(item => ({ json: { ...item.json, url_hash: hashUrl(item.json.url) } }));

// Get existing hashes from search response
const existing = new Set(
  ($input.first().json?.data?.results || []).map(r => r.url_hash).filter(Boolean)
);
// Re-attach original items (stored in $('Attach URL Hashes').all())
const all = $('Attach URL Hashes').all();
const seen = new Set();
const newItems = [];
for (const item of all) {
  const h = item.json.url_hash;
  if (!existing.has(h) && !seen.has(h)) {
    newItems.push(item);
    seen.add(h);
  } else {
    console.log('[DEDUP] skipped:', item.json.url);
  }
}
console.log(`[DEDUP] new=${newItems.length} skipped=${all.length - newItems.length}`);
return newItems;
